+            return Err(Error::QeIdentityVerificationFailed(format!(
+                "ISVSVN {} exceeds maximum allowed version {}",
+                qe_report.body.isvsvn, max_isvsvn
+            )));
+        }
+    }
+    
+    Ok(())
