+/// Extract public key from a certificate
+fn extract_public_key_from_cert(cert: &Certificate) -> Result<Vec<u8>, Error> {
+    use x509_cert::der::Decode;
+    
+    let spki = &cert.tbs_certificate.subject_public_key_info;
+    
+    // Extract the public key bytes based on the algorithm
+    let algorithm = spki.algorithm.oid.to_string();
+    
+    match algorithm.as_str() {
+        "1.2.840.10045.2.1" => {
+            // ECDSA public key
+            let public_key_bytes = spki.subject_public_key.as_bytes()
+                .ok_or_else(|| Error::CertificateError("Invalid public key format".to_string()))?;
+            Ok(public_key_bytes.to_vec())
+        }
+        _ => Err(Error::CertificateError(
+            format!("Unsupported public key algorithm: {}", algorithm)
+        ))
+    }
+}
